43	
44	  // Component base premiums
45	  it("quote single rune → 25 G base + 5 fee = 30 G", () => {
46	    const result = run({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 30 }] });
51	  });
52	  it("quote single moonstone → 25 G base + 5 fee = 30 G", () => {
53	    const result = run({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "moonstone" }] }],
