59	
60	  // Block of 3 alike components
61	  it("quote 2 runes → 50 G base + 5 fee = 55 G", () => {
62	    const result = run({
63	      customer: { yearsWithMHPCO: 0 },
64	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
