80	  it.todo("quote 4 runes → 100 G base (no block, requires exactly 3) + 5 fee = 105 G");
81	  it.todo("quote 7 runes → 175 G base + 5 fee = 180 G");
82	
83	  // Alike components — different types do not form a block together
84	  it.todo("quote 2 runes + 1 moonstone → 75 G base + 5 fee = 80 G");
85	  it.todo("quote 3 runes + 3 moonstones → 120 G base (two separate blocks) + 5 fee = 125 G");
