87	  // Item-specific modifiers: cursed surcharge applies to the cursed item only
88	  it.todo("quote cursed sword on item-only scope → 100 + 50 curse + 5 fee = 155 G");
89	
90	  // High enchantment item-specific
91	  it.todo("quote sword enchantment 5 → 100 + 30 high-enchant + 5 fee = 135 G (threshold)");
92	  it.todo("quote sword enchantment 4 → 100 + 5 fee = 105 G (below threshold)");
93	  it.todo("quote cursed sword enchantment 5 → 100 + 50 + 30 + 5 = 185 G");
94	
95	  // Policy-wide modifiers
96	  it.todo("quote cursed sword + plain amulet → 160 base + 50 curse + 5 fee = 215 G");
97	  it.todo("quote single sword with customer 2 years → 100 - 20 loyalty + 5 fee = 85 G (threshold)");
98	  it.todo("first quote in scenario triggers first insurance surcharge → 100 + 10 + 5 = 115 G");
99	  it.todo("second quote in scenario gets follow-up contract discount → 100 + 10 first ins - 15 follow-up + 5 = 100 G");
