112	  it.todo("claim regular sword damage 500 → payout 400 (full minus 100 deductible)");
113	  it.todo("claim rune damage 200 → payout 100 (full minus 100 deductible)");
114	
115	  // Claims — enchantment >= 8 (50%)
116	  it.todo("claim steel sword ench 9 damage 1000 → payout 400 (50% then deductible)");
117	
118	  // Claims — dragon material full
119	  it.todo("claim dragon sword ench 5 damage 800 → payout 700 (full then deductible)");
120	
121	  // Claims — both clauses, 50% wins
122	  it.todo("claim dragon sword ench 9 damage 1000 → payout 400 (50% wins, then deductible)");
123	  it.todo("claim dragon sword ench 8 damage 1000 → payout 400 (high-ench threshold then deductible)");
124	
125	  // Deductible per damaged item
126	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
127	
128	  // Multiple items same type
129	  it.todo("policy with two swords, two sword damages → both processed separately");
130	  it.todo("claim with more damages of a type than insured → throws");
131	
132	  // Cap exhaustion
133	  it.todo("sword cap 2000; two claims 1500 each → first payout 1400 cap 600, second payout 600 cap 0");
134	  it.todo("cap based on unmodified insurance value (cursed sword cap 2000)");
135	  it.todo("sword + 3 runes insurance sum 1750 (block discount doesn't affect insurance sum)");
136	
137	  // Claims — payout rounding (down in MHPCO's favor)
138	  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");
139	
140	  // Claims — errors
141	  it.todo("claim for item not in policy throws");
142	  it.todo("claim with negative damage amount throws");
143	});
