1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	const BLOCK_PREMIUM = 60;
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	const sumBasePremiums = (items: Item[]) => {
20	  const isAllRunesBlock =
21	    items.length === 3 &&
22	    items.every((i) => i.type === "rune" && COMPONENT_TYPES.has(i.type));
23	  if (isAllRunesBlock) return BLOCK_PREMIUM;
24	  return items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
25	};
26	
27	const quote = (step: QuoteStep) => ({
28	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
29	});
30	
31	export const run = (input: Scenario): unknown => ({
32	  results: input.steps.map(quote),
33	});
